/**
 * Box sprinkles - types, config, and style generator for Box component.
 */

import { boxSprinkles, type BoxSprinkles } from "./Box.sprinkles.css";
import type {
  SpacingKey,
  MarginValue,
  Responsive,
} from "../_internal/sprinkles/types";
import { assignProp } from "../_internal/sprinkles/utils";

// ═══════════════════════════════════════════════════════════════════════════════
// TYPES & CONFIG
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * Box layout props - Tailwind-style shorthand props for padding and margin.
 *
 * All props support responsive values via an object with breakpoint keys:
 * - `base`: All screen sizes (mobile-first default)
 * - `sm`: 640px and up
 * - `md`: 768px and up
 * - `lg`: 1024px and up
 * - `xl`: 1280px and up
 * - `2xl`: 1536px and up
 *
 * @example
 * // Responsive padding: 8px on mobile, 16px on md+, 24px on lg+
 * <Box p={{ base: "8", md: "16", lg: "24" }} />
 */
export interface BoxLayoutProps {
  // Padding
  /**
   * Padding on all sides.
   * @example
   * // Static value
   * <Box p="16" />
   * @example
   * // Responsive: 8px on mobile, 16px on md+, 24px on lg+
   * <Box p={{ base: "8", md: "16", lg: "24" }} />
   */
  p?: Responsive<SpacingKey> | undefined;
  /**
   * Padding top.
   * @example
   * // Static value
   * <Box pt="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box pt={{ base: "4", md: "8" }} />
   */
  pt?: Responsive<SpacingKey> | undefined;
  /**
   * Padding right.
   * @example
   * // Static value
   * <Box pr="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box pr={{ base: "4", md: "8" }} />
   */
  pr?: Responsive<SpacingKey> | undefined;
  /**
   * Padding bottom.
   * @example
   * // Static value
   * <Box pb="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box pb={{ base: "4", md: "8" }} />
   */
  pb?: Responsive<SpacingKey> | undefined;
  /**
   * Padding left.
   * @example
   * // Static value
   * <Box pl="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box pl={{ base: "4", md: "8" }} />
   */
  pl?: Responsive<SpacingKey> | undefined;
  /**
   * Padding on the horizontal axis (left and right).
   * @example
   * // Static value
   * <Box px="16" />
   * @example
   * // Responsive: 8px on mobile, 16px on md+
   * <Box px={{ base: "8", md: "16" }} />
   */
  px?: Responsive<SpacingKey> | undefined;
  /**
   * Padding on the vertical axis (top and bottom).
   * @example
   * // Static value
   * <Box py="12" />
   * @example
   * // Responsive: 8px on mobile, 12px on md+
   * <Box py={{ base: "8", md: "12" }} />
   */
  py?: Responsive<SpacingKey> | undefined;

  // Margin
  /**
   * Margin on all sides.
   * @example
   * // Static value
   * <Box m="16" />
   * @example
   * // Responsive: 8px on mobile, 16px on md+
   * <Box m={{ base: "8", md: "16" }} />
   */
  m?: Responsive<MarginValue> | undefined;
  /**
   * Margin top.
   * @example
   * // Static value
   * <Box mt="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box mt={{ base: "4", md: "8" }} />
   */
  mt?: Responsive<MarginValue> | undefined;
  /**
   * Margin right.
   * @example
   * // Static value
   * <Box mr="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box mr={{ base: "4", md: "8" }} />
   */
  mr?: Responsive<MarginValue> | undefined;
  /**
   * Margin bottom.
   * @example
   * // Static value
   * <Box mb="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box mb={{ base: "4", md: "8" }} />
   */
  mb?: Responsive<MarginValue> | undefined;
  /**
   * Margin left.
   * @example
   * // Static value
   * <Box ml="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Box ml={{ base: "4", md: "8" }} />
   */
  ml?: Responsive<MarginValue> | undefined;
  /**
   * Margin on the horizontal axis (left and right). Use `"auto"` to center horizontally.
   * @example
   * // Static value
   * <Box mx="16" />
   * @example
   * // Center horizontally
   * <Box mx="auto" />
   * @example
   * // Responsive: 8px on mobile, auto (centered) on md+
   * <Box mx={{ base: "8", md: "auto" }} />
   */
  mx?: Responsive<MarginValue> | undefined;
  /**
   * Margin on the vertical axis (top and bottom).
   * @example
   * // Static value
   * <Box my="12" />
   * @example
   * // Responsive: 8px on mobile, 12px on md+
   * <Box my={{ base: "8", md: "12" }} />
   */
  my?: Responsive<MarginValue> | undefined;
}

// ═══════════════════════════════════════════════════════════════════════════════
// STYLE GENERATOR
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * Generate className for Box props.
 */
export function boxStyles(props: BoxLayoutProps): string {
  const sprinkleProps: BoxSprinkles = {};

  // Padding
  assignProp(sprinkleProps, "padding", props.p);
  assignProp(sprinkleProps, "paddingTop", props.pt);
  assignProp(sprinkleProps, "paddingRight", props.pr);
  assignProp(sprinkleProps, "paddingBottom", props.pb);
  assignProp(sprinkleProps, "paddingLeft", props.pl);
  assignProp(sprinkleProps, "paddingX", props.px);
  assignProp(sprinkleProps, "paddingY", props.py);

  // Margin
  assignProp(sprinkleProps, "margin", props.m);
  assignProp(sprinkleProps, "marginTop", props.mt);
  assignProp(sprinkleProps, "marginRight", props.mr);
  assignProp(sprinkleProps, "marginBottom", props.mb);
  assignProp(sprinkleProps, "marginLeft", props.ml);
  assignProp(sprinkleProps, "marginX", props.mx);
  assignProp(sprinkleProps, "marginY", props.my);

  return boxSprinkles(sprinkleProps);
}
